module decade_counter (
	input clk,
	input reset,
	output reg [7:0] count);

	always @(posedge clk) begin
		if (reset)
			count <= 8'b00000000;
		else if (count == 8'd9)
			count <= 8'b00000000;
		else
			count <= count + 1;
	end

  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        count <= 8'b11111111;
      end else if (count == 8'd0) begin
        count <= 8'b11111111;
      end else begin
        count <= count - 1;
      end;
    end
  end

endmodule

